package com.example.pbl.ui.layout

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.navigation.NavController
import com.example.pbl.ui.components.*
import com.example.pbl.ui.uihelpers.CardContentWrapper
import com.example.pbl.ui.theme.*
import com.example.pbl.ui.uihelpers.ValidatedTextField
import com.example.pbl.ui.uihelpers.ValidationType
import com.google.firebase.auth.FirebaseAuth

@Composable
fun SignInPage(navController: NavController) {
    var email    by remember { mutableStateOf("") }
    var password by remember { mutableStateOf("") }
    var emailError by remember { mutableStateOf("") }
    var passwordError by remember { mutableStateOf("") }
    var generalError by remember { mutableStateOf("") }
    val auth     = FirebaseAuth.getInstance()

    // Per-rule password hints for sign-in (same rules, helps user remember)
    val pwRules = listOf(
        Triple(registerPasswordHint1, errorRegisterPassword1, password.length >= 10),
        Triple(registerPasswordHint2, errorRegisterPassword2, password.any { it.isUpperCase() }),
        Triple(registerPasswordHint3, errorRegisterPassword3, password.any { it.isDigit() }),
        Triple(registerPasswordHint4, errorRegisterPassword4, password.any { !it.isLetterOrDigit() })
    )

    Surface(
        modifier = Modifier
            .fillMaxSize()
            .statusBarsPadding(),
        color = MaterialTheme.colorScheme.primary
    ) {
        Column(
            modifier = Modifier.fillMaxSize(),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Spacer(modifier = Modifier.height(50.dp))

            Loginpageimg()

            Spacer(modifier = Modifier.height(50.dp))

            AppStaticFilledCard(
                modifier       = Modifier.fillMaxWidth().fillMaxHeight(),
                containerColor = MaterialTheme.colorScheme.background,
                contentColor   = MaterialTheme.colorScheme.primary
            ) {
                CardContentWrapper {
                    Column(
                        modifier             = Modifier.fillMaxSize(),
                        verticalArrangement  = Arrangement.spacedBy(16.dp),
                        horizontalAlignment  = Alignment.CenterHorizontally
                    ) {
                        Text(
                            signIn,
                            style    = MaterialTheme.typography.titleLarge,
                            modifier = Modifier.padding(top = 24.dp, bottom = 4.dp)
                        )

                        Text(
                            signInSubtitle,
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )

                        Spacer(modifier = Modifier.height(8.dp))

                        // Email — shows inline error when format is wrong
                        ValidatedTextField(
                            value          = email,
                            onValueChange  = {
                                email = it
                                emailError = "" // Clear error when user types
                            },
                            placeholder    = signUpEmail,
                            modifier       = Modifier.fillMaxWidth(),
                            validationType = ValidationType.EMAIL
                        )

                        if (emailError.isNotEmpty()) {
                            Text(
                                text = emailError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, top = 2.dp).align(Alignment.Start)
                            )
                        }

                        // Password — per-rule hint rows
                        ValidatedTextField(
                            value         = password,
                            onValueChange = {
                                password = it
                                passwordError = "" // Clear error when user types
                            },
                            placeholder   = password,
                            modifier      = Modifier.fillMaxWidth(),
                            hintRows      = pwRules
                        )

                        if (passwordError.isNotEmpty()) {
                            Text(
                                text = passwordError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, top = 2.dp).align(Alignment.Start)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // General error display
                        if (generalError.isNotEmpty()) {
                            Text(
                                text = generalError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, bottom = 4.dp).align(Alignment.Start)
                            )
                        }

                        AppFilledButton(
                            modifier = Modifier.fillMaxWidth(),
                            onClick  = {
                                if (email.isNotEmpty() && password.isNotEmpty()) {
                                    auth.signInWithEmailAndPassword(email, password)
                                        .addOnCompleteListener { task ->
                                            if (task.isSuccessful) navController.navigate("home") {
                                                popUpTo("login") { inclusive = true }
                                            }
                                        }
                                }
                            }
                        ) {
                            Text(signInButton)
                        }

                        AppTextButton(
                            onClick      = { navController.navigate("register") },
                            contentColor = MaterialTheme.colorScheme.primary
                        ) {
                            Text(signInNoAccount)
                        }
                    }
                }
            }
        }
    }
}

package com.example.pbl.ui.layout

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.navigation.NavController
import com.example.pbl.ui.components.*
import com.example.pbl.ui.uihelpers.CardContentWrapper
import com.example.pbl.ui.theme.*
import com.example.pbl.ui.uihelpers.ValidatedTextField
import com.example.pbl.ui.uihelpers.ValidationType
import com.google.firebase.auth.FirebaseAuth

@Composable
fun SignInPage(navController: NavController) {
    var email    by remember { mutableStateOf("") }
    var password by remember { mutableStateOf("") }
    var emailError by remember { mutableStateOf("") }
    var passwordError by remember { mutableStateOf("") }
    var generalError by remember { mutableStateOf("") }
    val auth     = FirebaseAuth.getInstance()

    // Per-rule password hints for sign-in (same rules, helps user remember)
    val pwRules = listOf(
        Triple(registerPasswordHint1, errorRegisterPassword1, password.length >= 10),
        Triple(registerPasswordHint2, errorRegisterPassword2, password.any { it.isUpperCase() }),
        Triple(registerPasswordHint3, errorRegisterPassword3, password.any { it.isDigit() }),
        Triple(registerPasswordHint4, errorRegisterPassword4, password.any { !it.isLetterOrDigit() })
    )

    Surface(
        modifier = Modifier
            .fillMaxSize()
            .statusBarsPadding(),
        color = MaterialTheme.colorScheme.primary
    ) {
        Column(
            modifier = Modifier.fillMaxSize(),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Spacer(modifier = Modifier.height(50.dp))

            Loginpageimg()

            Spacer(modifier = Modifier.height(50.dp))

            AppStaticFilledCard(
                modifier       = Modifier.fillMaxWidth().fillMaxHeight(),
                containerColor = MaterialTheme.colorScheme.background,
                contentColor   = MaterialTheme.colorScheme.primary
            ) {
                CardContentWrapper {
                    Column(
                        modifier             = Modifier.fillMaxSize(),
                        verticalArrangement  = Arrangement.spacedBy(16.dp),
                        horizontalAlignment  = Alignment.CenterHorizontally
                    ) {
                        Text(
                            signIn,
                            style    = MaterialTheme.typography.titleLarge,
                            modifier = Modifier.padding(top = 24.dp, bottom = 4.dp)
                        )

                        Text(
                            signInSubtitle,
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )

                        Spacer(modifier = Modifier.height(8.dp))

                        // Email — shows inline error when format is wrong
                        ValidatedTextField(
                            value          = email,
                            onValueChange  = {
                                email = it
                                emailError = "" // Clear error when user types
                            },
                            placeholder    = signUpEmail,
                            modifier       = Modifier.fillMaxWidth(),
                            validationType = ValidationType.EMAIL
                        )

                        if (emailError.isNotEmpty()) {
                            Text(
                                text = emailError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, top = 2.dp).align(Alignment.Start)
                            )
                        }

                        // Password — per-rule hint rows
                        ValidatedTextField(
                            value         = password,
                            onValueChange = {
                                password = it
                                passwordError = "" // Clear error when user types
                            },
                            placeholder   = password,
                            modifier      = Modifier.fillMaxWidth(),
                            hintRows      = pwRules
                        )

                        if (passwordError.isNotEmpty()) {
                            Text(
                                text = passwordError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, top = 2.dp).align(Alignment.Start)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // General error display
                        if (generalError.isNotEmpty()) {
                            Text(
                                text = generalError,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.error,
                                modifier = Modifier.padding(start = 4.dp, bottom = 4.dp).align(Alignment.Start)
                            )
                        }

                        AppFilledButton(
                            modifier = Modifier.fillMaxWidth(),
                            onClick  = {
                                // Clear previous errors
                                emailError = ""
                                passwordError = ""
                                generalError = ""

                                if (email.isEmpty()) {
                                    emailError = errorInputBlank
                                    return@onClick
                                }
                                if (password.isEmpty()) {
                                    passwordError = errorInputBlank
                                    return@onClick
                                }

                                auth.signInWithEmailAndPassword(email, password)
                                    .addOnCompleteListener { task ->
                                        if (task.isSuccessful) {
                                            navController.navigate("home") {
                                                popUpTo("login") { inclusive = true }
                                            }
                                        } else {
                                            // Handle Firebase errors
                                            val exception = task.exception
                                            generalError = when (exception?.message) {
                                                // Firebase error codes
                                                "There is no user record corresponding to this identifier. The user may have been deleted." -> errorLoginEmail
                                                "The password is invalid or the user does not have a password." -> errorLoginPassword
                                                else -> {
                                                    // Check if it's an invalid email format error
                                                    if (exception?.message?.contains("email") == true) {
                                                        errorLoginInvalidEmail
                                                    } else {
                                                        exception?.message ?: "Sign in failed. Please try again."
                                                    }
                                                }
                                            }
                                        }
                                    }
                            }
                        ) {
                            Text(signInButton)
                        }

                        AppTextButton(
                            onClick      = { navController.navigate("register") },
                            contentColor = MaterialTheme.colorScheme.primary
                        ) {
                            Text(signInNoAccount)
                        }
                    }
                }
            }
        }
    }
}

