    onValueChange: (String) -> Unit,
    placeholder: String,
    modifier: Modifier = Modifier,
    validationType: ValidationType = ValidationType.GENERAL,
    hintRows: List<Triple<String, String, Boolean>> = emptyList(),
    hasBeenFocused: Boolean = false,
    shouldValidate: Boolean = false,
    onFocusChanged: ((Boolean) -> Unit)? = null,
    containerColor: Color = MaterialTheme.colorScheme.primaryContainer,
    contentColor: Color = MaterialTheme.colorScheme.onPrimaryContainer,
    focusedContainerColor: Color = MaterialTheme.colorScheme.primary,
    focusedContentColor: Color = MaterialTheme.colorScheme.onPrimary,
    singleLine: Boolean = true
) {
    val interactionSource = remember { MutableInteractionSource() }
    val isFocused by interactionSource.collectIsFocusedAsState()

    // Track focus changes
    androidx.compose.runtime.LaunchedEffect(isFocused) {
        if (isFocused && !hasBeenFocused) {
            onFocusChanged?.invoke(true)
        }
    }

    Column(modifier = modifier) {
        AppTextField(
            value = value,
            onValueChange = onValueChange,
            placeholder = placeholder,
            modifier = Modifier.fillMaxWidth(),
            interactionSource = interactionSource,
            containerColor = containerColor,
            contentColor = contentColor,
            focusedContainerColor = focusedContainerColor,
            focusedContentColor = focusedContentColor,
            singleLine = singleLine
        )

        if (hintRows.isNotEmpty()) {
            // hint rows with new behavior
            hintRows.forEach { (hint, errorMsg, isPassed) ->
                FieldHintRow(
                    hint = hint,
                    errorMsg = errorMsg,
                    isPassed = isPassed,
                    isFocused = isFocused,
                    hasBeenFocused = hasBeenFocused,
                    shouldValidate = shouldValidate
                )
            }
        } else if (validationType != ValidationType.GENERAL && !value.isEmpty()) {
            val result = validateUserInput(value, validationType)
            if (result is ValidationResult.Error) {
                Text(
                    text = result.message,
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.error,
                    modifier = Modifier.padding(start = 4.dp, top = 2.dp)
                )
            }
        }
    }
}

// wrapper
@Composable
fun TextFieldContentWrapper(
    modifier: Modifier = Modifier,
    content: @Composable () -> Unit
) {
    Box(modifier = modifier.padding(16.dp)) {
        content()
    }
}

package com.example.pbl.ui.components

import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.Spacer
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.layout.size
import androidx.compose.foundation.layout.width
import androidx.compose.material3.Icon
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.res.painterResource
import androidx.compose.ui.unit.dp
import com.example.pbl.R
import com.example.pbl.ui.theme.PBLTheme

// for them line beneath the textfield - only shows when focused
@Composable
fun FieldHintRow(
    hint: String,
    errorMsg: String,
    isPassed: Boolean,
    isFocused: Boolean,
    modifier: Modifier = Modifier
) {
    // Only show hints when the field is focused
    if (!isFocused) return

    val customColors = PBLTheme.colors
    val tint: Color
    val label: String
    val showIcon: Boolean

    when {
        isPassed -> {
            tint     = customColors.success
            label    = hint
            showIcon = true
        }
        else -> {
            tint     = MaterialTheme.colorScheme.error
            label    = errorMsg
            showIcon = true
        }
    }

    Row(
        modifier = modifier.padding(start = 4.dp, top = 2.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        if (showIcon) {
            val iconRes = if (isPassed) R.drawable.green_check else R.drawable.red_cross
            Icon(
                painter = painterResource(iconRes),
                contentDescription = null,
                tint = tint,
                modifier = Modifier.size(12.dp)
            )
        } else {
            Text(
                text = "\u2022",
                color = tint,
                style = MaterialTheme.typography.labelSmall
            )
        }
        Spacer(Modifier.width(4.dp))
        Text(
            text = label,
            style = MaterialTheme.typography.labelSmall,
            color = tint
        )
    }
}

package com.example.pbl.ui.components

import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.Spacer
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.layout.size
import androidx.compose.foundation.layout.width
import androidx.compose.material3.Icon
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.res.painterResource
import androidx.compose.ui.unit.dp
import com.example.pbl.R
import com.example.pbl.ui.theme.PBLTheme

// for them line beneath the textfield - only shows when focused or has been focused
@Composable
fun FieldHintRow(
    hint: String,
    errorMsg: String,
    isPassed: Boolean,
    isFocused: Boolean,
    hasBeenFocused: Boolean,
    shouldValidate: Boolean,
    modifier: Modifier = Modifier
) {
    // Show hints if currently focused OR has been focused before
    if (!isFocused && !hasBeenFocused) return

    val customColors = PBLTheme.colors
    val tint: Color
    val label: String
    val showIcon: Boolean

    when {
        !shouldValidate -> {
            // Before validation: show grey hint with bullet
            tint = Color.Gray
            label = hint
            showIcon = false
        }
        isPassed -> {
            tint = customColors.success
            label = hint
            showIcon = true
        }
        else -> {
            tint = MaterialTheme.colorScheme.error
            label = errorMsg
            showIcon = true
        }
    }

    Row(
        modifier = modifier.padding(start = 4.dp, top = 2.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        if (showIcon) {
            val iconRes = if (isPassed) R.drawable.green_check else R.drawable.red_cross
            Icon(
                painter = painterResource(iconRes),
                contentDescription = null,
                tint = tint,
                modifier = Modifier.size(12.dp)
            )
        } else {
            Text(
                text = "\u2022",
                color = tint,
                style = MaterialTheme.typography.labelSmall
            )
        }
        Spacer(Modifier.width(4.dp))
        Text(
            text = label,
            style = MaterialTheme.typography.labelSmall,
            color = tint
        )
    }
}
